  1→import { lazy, Suspense } from 'react'
  2→import './App.css'
  3→import { Routes, Route, BrowserRouter, Navigate} from 'react-router-dom'
  4→import { useAuth } from './Context/useAuth.js';
  5→import { LexicalComposer } from '@lexical/react/LexicalComposer';
  6→import { EDITOR_NODES, EDITOR_THEME } from './components/HomePage/Editor/editorConfig.js';
  7→import Loader from './components/loadingComponent/BgLoader.jsx';
  8→import SeoManager from './seo/SeoManager.jsx';
  9→import ProtectedRoute from './components/ProtectedRoute.jsx';
 10→
 11→const NotFound = lazy(() => import('./components/NotFound.jsx'));
 12→
 13→const AuthModal = lazy(() => import('./components/AuthModal/AuthModal.jsx'));
 14→const HomePage = lazy(() => import('./components/HomePage/Home.jsx'));
 15→const LoginPage = lazy(() => import('./components/LoginPage/login.jsx'));
 16→const SignUp = lazy(() => import('./components/SignUpPage/signup.jsx'));
 17→const MyProfile = lazy(() => import('./components/ProfilePage/MyProfile.jsx'));
 18→const PostCards = lazy(() => import('./components/HomePage/postCards/PostCards.jsx'));
 19→const ContentView = lazy(() => import('./components/HomePage/ContentViewer/ContentView.jsx'));
 20→const Bookmarks = lazy(() => import('./components/Bookmarks/Bookmarks.jsx'));
 21→const Visitprofile = lazy(() => import('./components/VisitProfile/Visitprofile.jsx'));
 22→const ProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/ProfilePostCards.jsx'));
 23→const ProfileMediaSection = lazy(() => import('./components/ProfilePage/components/ProfileMediaSection.jsx'));
 24→const VisitedProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/VisitedProfilePostCards.jsx'));
 25→const VisitedProfileMediaSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileMediaSection.jsx'));
 26→const Notifications = lazy(() => import('./components/Notifications/Notifications.jsx'));
 27→const NotificationCards = lazy(() => import('./components/Notifications/notificationsCards.jsx'));
 28→const UnreadNotification = lazy(() => import('./components/Notifications/UnreadNotificationCard.jsx'));
 29→const OpinionsPage = lazy(() => import('./components/SidebarOpinions/OpinionssPage.jsx'));
 30→const VisitedProfileOpinions = lazy(() => import('./components/SidebarOpinions/visitedProfileOpinions.jsx'));
 31→const MyOpinions = lazy(() => import('./components/SidebarOpinions/MyOpinions.jsx'));
 32→const OpinionViewer = lazy(() => import('./components/SidebarOpinions/opinionViewer.jsx'));
 33→const ExplorePage = lazy(() => import('./components/HomePage/explore/ExplorePage.jsx'));
 34→const SettingsPage = lazy(() => import('./components/SettingsPage/SettingsPage.jsx'));
 35→const DraftList = lazy(() => import('./components/HomePage/Editor/DraftList/DraftList.jsx'));
 36→const AnalyticsDashboard = lazy(() => import('./components/Analytics/AnalyticsDashboard.jsx'));
 37→const StoryDashboard = lazy(() => import('./components/Stories/StoryDashboard/StoryDashboard.jsx'));
 38→const StoryEditor = lazy(() => import('./components/Stories/StoryEditor/StoryEditor.jsx'));
 39→const StoryChapterManager = lazy(() => import('./components/Stories/StoryChapterManager/StoryChapterManager.jsx'));
 40→const ChapterEditor = lazy(() => import('./components/Stories/ChapterEditor/ChapterEditor.jsx'));
 41→const StoryBrowser = lazy(() => import('./components/Stories/StoryBrowser/StoryBrowser.jsx'));
 42→const StoryLibrary = lazy(() => import('./components/Stories/StoryLibrary/StoryLibrary.jsx'));
 43→const StoryDetail = lazy(() => import('./components/Stories/StoryDetail/StoryDetail.jsx'));
 44→const ChapterReader = lazy(() => import('./components/Stories/ChapterReader/ChapterReader.jsx'));
 45→const ProfileStoriesSection = lazy(() => import('./components/ProfilePage/components/ProfileStoriesSection.jsx'));
 46→const VisitedProfileStoriesSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileStoriesSection.jsx'));
 47→
 48→const editorConfig = {
 49→  namespace: "MyLexicalEditor",
 50→  theme: EDITOR_THEME,
 51→  nodes: EDITOR_NODES,
 52→  onError(error){
 53→    throw error;
 54→  },
 55→};
 56→
 57→const AppAuthModal = () => {
 58→  const {showAuthModal, closeAuthModal} = useAuth();
 59→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 60→}
 61→
 62→const AppSplash = () => {
 63→  const { loading } = useAuth();
 64→  return <Loader isLoading={loading} />;
 65→}
 66→
 67→const HomeWithEditor = () => (
 68→  <LexicalComposer initialConfig={editorConfig}>
 69→    <HomePage/>
 70→  </LexicalComposer>
 71→);
 72→
 73→const SuspenseFallback = () => (
 74→  <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
 75→    <Loader />
 76→  </div>
 77→);
 78→
 79→const App = () => {
 80→
 81→  return (
 82→    <>
 83→      <BrowserRouter>
 84→        <SeoManager />
 85→        <AppSplash />
 86→        <Suspense fallback={<SuspenseFallback />}>
 87→          <AppAuthModal/>
 88→          <Routes>
 89→            <Route path='/' element={<Navigate to='/home' replace/>}/>
 90→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
 91→            <Route path='/profile' element={<ProtectedRoute><MyProfile/></ProtectedRoute>}>
 92→              <Route index element={<ProfilePostCards/>} />
 93→              <Route path='media' element={<ProfileMediaSection/>} />
 94→              <Route path='myOpinions' element={<MyOpinions/>}/>
 95→              <Route path='stories' element={<ProfileStoriesSection/>}/>
 96→            </Route>
 97→
 98→            <Route path='/visitProfile' element={<Visitprofile/>}>
 99→              <Route index element={<VisitedProfilePostCards/>}/>
100→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
101→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
102→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
103→            </Route>
104→
105→            <Route path='/u/:username' element={<Visitprofile/>}>
106→              <Route index element={<VisitedProfilePostCards/>}/>
107→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
108→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
109→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
110→            </Route>
111→
112→            <Route path='/home' element={<HomeWithEditor/>}>
113→              <Route index element={<PostCards/>}/>
114→              <Route path='following' element={<PostCards/>}/>
115→              <Route path='for-you' element={<PostCards/>}/>
116→              <Route path='explore' element={<ExplorePage/>}/>
117→              <Route path='contentViewer' element={<ContentView/>}/>
118→              <Route path='post/:journalId' element={<ContentView/>}/>
119→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
120→              <Route path='bookmark' element={<Bookmarks/>}/>
121→              <Route path='opinions'element={<OpinionsPage/>}/>
122→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
123→
124→              <Route path='drafts' element={<DraftList/>}/>
125→              <Route path='analytics' element={<AnalyticsDashboard/>}/>
126→              <Route path='settings' element={<SettingsPage/>}/>
127→
128→              {/* Stories routes */}
129→              <Route path='stories' element={<StoryBrowser/>}/>
130→              <Route path='stories/library' element={<StoryLibrary/>}/>
131→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
132→              <Route path='stories/new' element={<StoryEditor/>}/>
133→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
134→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
135→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
136→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
137→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
138→
139→              {/* route for nested notifications */}
140→              <Route path='notifications' element={<Notifications/>}>
141→                <Route index element={<NotificationCards/>}/>
142→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
143→              </Route>
144→            </Route>
145→
146→            <Route path='/login' element={<LoginPage/>}/>
147→            <Route path='/signUp' element={<SignUp/>}/>
148→            <Route path='*' element={<NotFound/>}/>
149→          </Routes>
150→        </Suspense>
151→      </BrowserRouter>
152→    </>
153→  )
154→}
155→
156→export default App
